import React from 'react';
import { Accordion } from './Accordion';
import type { AccordionItem } from './Accordion';

const faqItems: AccordionItem[] = [
  {
    id: '1',
    title: 'What is React?',
    content:
      'React is a JavaScript library for building user interfaces. It lets you compose complex UIs from small, isolated pieces of code called components.',
  },
  {
    id: '2',
    title: 'What are hooks?',
    content:
      'Hooks are functions that let you use state and other React features in functional components. Common hooks include useState, useEffect, and useContext.',
  },
  {
    id: '3',
    title: 'What is JSX?',
    content:
      'JSX is a syntax extension for JavaScript that looks similar to HTML. It is used with React to describe what the UI should look like.',
  },
];

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>FAQ</h1>
      <Accordion items={faqItems} />
    </div>
  );
}

import React from 'react';
import './styles.css';

export interface AccordionItem {
  id: string;
  title: string;
  content: string;
}

interface AccordionProps {
  items: AccordionItem[];
}

export const Accordion: React.FC<AccordionProps> = ({ items }) => {
  // TODO: Track which section is currently expanded (or null)

  return (
    <div className="accordion">
      {items.map((item) => (
        <div key={item.id} className="accordion__item">
          <button
            data-testid={`header-${item.id}`}
            className="accordion__header"
            aria-expanded={false}
          >
            <span>{item.title}</span>
            <span className="accordion__icon">&#9656;</span>
          </button>
          {/* TODO: Conditionally render the panel only when this section is open */}
          <div
            data-testid={`panel-${item.id}`}
            className="accordion__panel"
            role="region"
          >
            <div className="accordion__content">{item.content}</div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default Accordion;

.accordion {
  width: 100%;
  max-width: 32rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
  overflow: hidden;
}

.accordion__item + .accordion__item {
  border-top: 1px solid #e5e7eb;
}

.accordion__header {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.875rem 1rem;
  background: #f9fafb;
  border: none;
  cursor: pointer;
  font-size: 0.9375rem;
  font-weight: 500;
  color: #1f2937;
  text-align: left;
  transition: background-color 0.15s ease;
}

.accordion__header:hover {
  background: #f3f4f6;
}

.accordion__header--open {
  background: #eff6ff;
  color: #1d4ed8;
}

.accordion__icon {
  font-size: 0.75rem;
  transition: transform 0.2s ease;
}

.accordion__header--open .accordion__icon {
  transform: rotate(90deg);
}

.accordion__content {
  padding: 0.875rem 1rem;
  font-size: 0.875rem;
  color: #4b5563;
  line-height: 1.6;
}

