import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { Accordion } from './Accordion';

const testItems = [
  { id: '1', title: 'Section One', content: 'Content for section one' },
  { id: '2', title: 'Section Two', content: 'Content for section two' },
  { id: '3', title: 'Section Three', content: 'Content for section three' },
];

describe('Accordion', () => {
  it('renders all section headers', () => {
    render(<Accordion items={testItems} />);
    expect(screen.getByTestId('header-1')).toHaveTextContent('Section One');
    expect(screen.getByTestId('header-2')).toHaveTextContent('Section Two');
    expect(screen.getByTestId('header-3')).toHaveTextContent('Section Three');
  });

  it('all sections start collapsed', () => {
    render(<Accordion items={testItems} />);
    expect(screen.queryByTestId('panel-1')).not.toBeInTheDocument();
    expect(screen.queryByTestId('panel-2')).not.toBeInTheDocument();
    expect(screen.queryByTestId('panel-3')).not.toBeInTheDocument();
  });

  it('expands a section when its header is clicked', () => {
    render(<Accordion items={testItems} />);
    fireEvent.click(screen.getByTestId('header-1'));
    expect(screen.getByTestId('panel-1')).toBeInTheDocument();
    expect(screen.getByTestId('panel-1')).toHaveTextContent('Content for section one');
  });

  it('collapses a section when its header is clicked again', () => {
    render(<Accordion items={testItems} />);
    fireEvent.click(screen.getByTestId('header-1'));
    fireEvent.click(screen.getByTestId('header-1'));
    expect(screen.queryByTestId('panel-1')).not.toBeInTheDocument();
  });

  it('closes the previous section when opening another', () => {
    render(<Accordion items={testItems} />);
    fireEvent.click(screen.getByTestId('header-1'));
    expect(screen.getByTestId('panel-1')).toBeInTheDocument();
    fireEvent.click(screen.getByTestId('header-2'));
    expect(screen.queryByTestId('panel-1')).not.toBeInTheDocument();
    expect(screen.getByTestId('panel-2')).toBeInTheDocument();
  });

  it('sets aria-expanded correctly', () => {
    render(<Accordion items={testItems} />);
    expect(screen.getByTestId('header-1')).toHaveAttribute('aria-expanded', 'false');
    fireEvent.click(screen.getByTestId('header-1'));
    expect(screen.getByTestId('header-1')).toHaveAttribute('aria-expanded', 'true');
    expect(screen.getByTestId('header-2')).toHaveAttribute('aria-expanded', 'false');
  });
});

